VALUES
  ('heelevel3-d0d1b9a2-moex-00375', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '關於舞弊預防程序和控制制度建立，下列敘述何者錯誤？', '["管理階層應負擔其建立舞弊預防程序和控制制度的主要責任", "公司法務人員應負責執行反舞弊程序和控制活動", "上市或上櫃公司的審計委員會是公司最高反舞弊的監督機構，應該擔負監督的責任", "會計師及查核人員主要責任，在辨識反舞弊機制是否有效降低因舞弊所產生的重大不實表達風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00376', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '查核人員於受查者存在關係人交易情況下之偵出重大不實表達的能力，受先天限制之潛在影響較 大，下列何者並非主要原因？', '["該類關係人交易金額並不重大", "管理階層可能未知悉所有關係人之關係及交易之存在", "關係人交易通常透過複雜結構的安排下進行", "關係人之關係可能給予管理階層共謀、隱匿及操縱之更佳機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00377', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關「分析性程序」，下列敘述何者正確？', '["查核人員可利用分析性程序，經考量租金、公寓數量及空屋率後，推估出租公寓之總租金收入", "銷貨訂單處理流程之控制若存有缺失，則關於應收帳款之聲明，查核人員可能較依賴證實分析 性程序，而非細項測試", "取得與應收帳款餘額之評價聲明有關之查核證據時，查核人員僅對帳齡執行分析性程序，以判 斷應收帳款之收現性即可完成", "分析性程序可考量財務資訊與攸關非財務資訊間之關係，例如最近3年之銷貨毛利率計算與比較"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00378', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依據審計準則510號（原審計準則公報第六十三號）「首次受託查核案件－期初餘額」之規定， 有關查核人員首次受託查核時，下列對期初餘額之查核對當期查核報告之影響敘述何者錯誤？', '["如查核人員無法對存貨之期初餘額取得足夠及適切之查核證據，會計師可能出具對綜合損益 表、權益變動表及現金流量表表示保留意見或無法表示意見，而對資產負債表表示無保留意見 之查核報告", "會計師如作出期初餘額所適用之會計政策未依適用之財務報導架構於本期一致適用之結論時， 則應表示保留意見或無法表示意見", "會計師如推斷期初餘額存有重大影響本期財務報表之不實表達，且其影響未適當處理、表達或 揭露，則應表示保留意見或否定意見", "如前任會計師對前期財務報表表示修正式意見，且導致修正式意見之事項對本期財務報表仍屬 攸關且重大，繼任會計師應對本期財務報表表示修正式意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00379', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依據審計準則之規定，下列與顯著風險有關之敘述何者錯誤？', '["查核人員就收入認列通常應先假設存有顯著風險", "查核人員在評估顯著風險前應先測試相關控制是否有效", "會計估計如涉及管理階層主觀判斷，且估計結果具高度不確定性，此等會計估計可能存有顯著 風險", "受查者之非正常營運之重大關係人交易應評估為顯著風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00380', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '甲公司主要係從事汽車銷售業務之上市公司，該公司2018年、2019年及2020年度銷貨收入分別 為50億、53億、38億元，稅前淨利分別為2.5億、3億及0.2億元，2020年度獲利衰退主要原 因係因受新型冠狀病毒疫情之影響，導致甲公司產品銷售量不足，甲公司認為等疫情結束，2021 年度以後應該能逐漸恢復2018年及2019年度之銷售量。會計師查核2018年及2019年度財務報 表於決定財務報表整體重大性係採用稅前淨利為基準，會計師針對 2020 年度查核如何決定適當 基準？', '["採用2018年、2019年及2020年度稅前淨利之平均數", "採用2018年、2019年及2020年度銷貨收入金額之平均數", "採用2020年度稅前淨利", "採用2020年度銷貨收入金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00381', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '集團查核團隊對組成個體財務資訊擬執行工作類型之決定，下列何者為正確之事項考量優先次', '["對非重要組成個體之財務資訊，執行分析性程序", "所規劃之範圍是否可取足夠及適切之 查核證據，以作為表示集團查核意見之依據", "組成個體是否具有個別財務重要性", "組成個體是 否因其特殊性質或情況，可能存有導致集團財務報表重大不實表達之顯著風險 ⑤對進一步所選 擇之非重要組成個體，執行工作類型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00382', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依據審計準則580號（原審計準則公報第六十六號）「書面聲明」之規定，下列有關受查者所出 具之書面聲明何者錯誤？', '["書面聲明之日期應儘量接近查核報告日，但不得晚於該日。書面聲明應涵蓋查核報告中提及之 所有財務報表與期間", "基於管理階層對查核案件條款中所述責任之認知與瞭解，管理階層對其認知與瞭解之再次確 認，可使用「就本公司所知」之限制性文字", "現任管理階層於查核報告中提及之所有期間可能並非均在職，於此情況下，查核人員仍須向現 任管理階層取得涵蓋所有期間之書面聲明", "查核人員對管理階層之誠信有重大懷疑，致其認為所取得之書面聲明並不可靠時，會計師應對 財務報表出具無法表示意見之查核報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00383', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何種情況最不可能影響對查核風險之判斷？', '["受查公司即將首次公開發行股票", "受查公司未於財務報表揭露關係人交易", "受查公司之會計部門主管流動率高", "受查公司每兩週即發一次員工薪水"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00384', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '針對受查者20X1年12月31日之所有銷貨收入執行認列時點之查核程序，查核人員發現有一筆 銷貨之交易條件約定為目的地交貨，買方係於 20X2 年 1 月 3 日簽收，但受查公司會計人員於 20X1年12月31日出貨後即認列收入，則該不實表達為：', '["實際不實表達", "判斷性不實表達", "推估不實表達", "預期不實表達"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
